import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { PoliceCallParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/PoliceCallParser';

export class PoliceCallEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, PoliceCallParser);
    }

    public getParser(): PoliceCallParser {
        return this.parser as PoliceCallParser;
    }
}
